"""family_fp16_5: FLOAT16-intermediate rebuilds of memory-dominated FP32 solvers.

For each target task the incumbent exact float32 graph (out_p5/onnx) is rebuilt so
every INTERMEDIATE tensor is float16 (2 bytes) instead of float32 (4 bytes), while
the graph I/O stays FLOAT[1,10,30,30] per the contract: a single Cast at the top
lowers ``input`` to float16, every float initializer/Constant is re-emitted in
float16 (clamped to the representable range), interior ``Cast``-to-float nodes are
retargeted to float16, and a final Cast lifts the result back to float32 before
``output``.  Same algorithm, half the dominant memory term -> lower cost.

The grader only thresholds ``(output > 0)`` and float16 is exact for the small
integer sums these graphs compute, so behaviour is byte-identical.  Only tasks
whose float16 rebuild is strictly CHEAPER than the incumbent are embedded (already
-float16 incumbents gain nothing).  Detection is behavioural + self-contained: each
embedded graph is run and proposed only when it reproduces every train+test pair
EXACTLY after the (>0) threshold, so it never fires on the wrong task and the
grader still validates arc-gen -- it generalises without memorising contents.
"""
from __future__ import annotations

import base64
import gzip

import numpy as np
import onnx

try:
    import onnxruntime as _ort
except Exception:  # pragma: no cover
    _ort = None

# task-number -> gzip+base64 of the float16 ONNX model
_MODELS = {
    19: "",
    77: "",
    105: "",
    119: "",
    128: "",
    137: "",
    145: "",
    153: "",
    159: "",
    196: "",
    237: "",
    243: "",
    313: "",
    325: "",
    390: "",
    394: "",
}

_SESS = {}


def _raw(t):
    return gzip.decompress(base64.b64decode(_MODELS[t]))


def _session(t):
    s = _SESS.get(t)
    if s is None:
        so = _ort.SessionOptions()
        so.graph_optimization_level = _ort.GraphOptimizationLevel.ORT_DISABLE_ALL
        so.log_severity_level = 3
        s = _ort.InferenceSession(_raw(t), so)
        _SESS[t] = s
    return s


def _onehot(grid):
    g = np.asarray(grid, dtype=np.int64)
    h, w = g.shape
    x = np.zeros((1, 10, 30, 30), dtype=np.float32)
    for r in range(h):
        row = g[r]
        for c in range(w):
            x[0, int(row[c]), r, c] = 1.0
    return x


def candidates(examples):
    if _ort is None:
        return []
    pairs = list(examples.get("train", [])) + list(examples.get("test", []))
    data = []
    for e in pairs:
        gi = np.asarray(e["input"]); go = np.asarray(e["output"])
        if gi.ndim != 2 or go.ndim != 2:
            continue
        if max(gi.shape) > 30 or max(go.shape) > 30:
            continue  # grader ignores >30x30 grids
        data.append((_onehot(gi), _onehot(go)))
    if not data:
        return []
    out = []
    for t in _MODELS:
        try:
            sess = _session(t)
        except Exception:
            continue
        ok = True
        for x, tg in data:
            try:
                y = sess.run(["output"], {"input": x})[0]
            except Exception:
                ok = False
                break
            yb = (np.asarray(y) > 0.0)
            if yb.shape != tg.shape or not np.array_equal(yb, tg > 0.0):
                ok = False
                break
        if ok:
            try:
                out.append((f"fp16_5_{t}", onnx.load_from_string(_raw(t))))
            except Exception:
                pass
    return out
